{"content":"<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Pokémon Gen 3 Style Web Battle</title>
<style>
    @font-face {
        font-family: 'PokemonFont';
        src: local('Courier New'); /* Fallback to monospace */
    }
    body {
        margin: 0;
        padding: 0;
        background-color: #222;
        display: flex;
        justify-content: center;
        align-items: center;
        height: 100vh;
        color: white;
        font-family: 'PokemonFont', 'Courier New', monospace;
    }
    #game-container {
        position: relative;
        width: 480px;
        height: 320px;
        background: #000;
        box-shadow: 0 0 20px rgba(0,0,0,0.8);
        overflow: hidden;
    }
    canvas {
        width: 100%;
        height: 100%;
        image-rendering: pixelated; /* Retro scaling */
    }
    #ui-layer {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        pointer-events: none;
    }
    /* GBA Dialog Box Style */
    #dialog-box {
        position: absolute;
        bottom: 0px;
        left: 0px;
        width: 100%;
        height: 80px; /* Scaled up for 480x320 */
        background: #f8f8f8;
        border: 4px solid #4a4a4a;
        border-radius: 6px;
        padding: 10px 16px;
        box-sizing: border-box;
        color: #2b2b2b;
        font-size: 20px;
        font-weight: bold;
        line-height: 1.4;
        display: none;
        z-index: 10;
        text-shadow: 1px 1px 0px #ccc;
    }
    #loading-screen {
        position: absolute;
        top: 0; left: 0; width: 100%; height: 100%;
        background: #000;
        display: flex;
        justify-content: center;
        align-items: center;
        z-index: 50;
        font-size: 20px;
        text-align: center;
    }
    .hidden { display: none !important; }
</style>
</head>
<body>

<div id="game-container">
    <canvas id="game-canvas" width="240" height="160"></canvas>
    <div id="ui-layer">
        <div id="dialog-box"></div>
        <div id="loading-screen">
            <div id="loading-text">Loading...</div>
        </div>
    </div>
</div>

<script>
// ==========================================
// CONSTANTS & UTILS
// ==========================================
const MAP_W = 240;
const MAP_H = 160;
const TILE_SIZE = 16;

// Gen 3 mechanics types
const SPECIAL_TYPES = ['Fire', 'Water', 'Grass', 'Electric', 'Psychic', 'Ice', 'Dragon', 'Dark'];

// ==========================================
// ASSET MANAGER
// ==========================================
const AssetManager = {
    images: {},
    async loadImage(key, url, fallbackColor) {
        return new Promise((resolve) => {
            const img = new Image();
            img.crossOrigin = 'Anonymous';
            img.onload = () => { this.images[key] = img; resolve(); };
            img.onerror = () => {
                console.warn(`Failed to load ${url}. Using placeholder.`);
                this.images[key] = this.createPlaceholder(64, 64, fallbackColor);
                resolve();
            };
            img.src = url;
        });
    },
    createPlaceholder(w, h, color) {
        const c = document.createElement('canvas');
        c.width = w; c.height = h;
        const ctx = c.getContext('2d');
        ctx.fillStyle = color;
        ctx.fillRect(0,0,w,h);
        return c;
    },
    async preloadAll(onComplete) {
        const textEl = document.getElementById('loading-text');
        try {
            // Load Emerald Sprites via PokeAPI
            // Player: Mudkip (258) Back, Enemy: Treecko (252) Front
            await Promise.all([
                this.loadImage('player_back', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/versions/generation-iii/emerald/back/258.png', '#0000ff'),
                this.loadImage('enemy_front', 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/versions/generation-iii/emerald/252.png', '#00ff00')
            ]);

            textEl.innerHTML = "Press Start<br><br><span style='font-size:14px'>(Press Z or Enter)</span>";
            const startHandler = (e) => {
                if(e.key === 'z' || e.key === 'Z' || e.key === 'Enter') {
                    window.removeEventListener('keydown', startHandler);
                    document.getElementById('loading-screen').classList.add('hidden');
                    onComplete();
                }
            };
            window.addEventListener('keydown', startHandler);
        } catch(e) {
            textEl.innerHTML = "Error loading game.";
        }
    }
};

// ==========================================
// INPUT HANDLER
// ==========================================
const Input = {
    keys: {},
    justPressed: {},
    locked: false,
    update() {
        for(let k in this.keys) {
            if(this.keys[k] && !this.justPressed[k + '_down']) {
                this.justPressed[k] = true;
                this.justPressed[k + '_down'] = true;
            } else {
                this.justPressed[k] = false;
            }
        }
    },
    isDown(key) { return !this.locked && !!this.keys[key]; },
    isJustPressed(key) { return !this.locked && !!this.justPressed[key]; },
    clearJustPressed(key) { this.justPressed[key] = false; }
};
window.addEventListener('keydown', e => { Input.keys[e.key.toLowerCase()] = true; });
window.addEventListener('keyup', e => { 
    Input.keys[e.key.toLowerCase()] = false; 
    Input.justPressed[e.key.toLowerCase() + '_down'] = false;
});

// ==========================================
// DIALOG SYSTEM
// ==========================================
const Dialog = {
    active: false,
    text: "",
    displayed: "",
    charIndex: 0,
    timer: 0,
    onComplete: null,
    el: null,
    init() { this.el = document.getElementById('dialog-box'); },
    show(text, onComplete) {
        this.active = true;
        this.text = text;
        this.displayed = "";
        this.charIndex = 0;
        this.onComplete = onComplete;
        this.el.style.display = 'block';
        this.el.innerHTML = "";
    },
    hide() {
        this.active = false;
        this.el.style.display = 'none';
        if(this.onComplete) this.onComplete();
    },
    update(dt) {
        if(!this.active) return;

        if(this.charIndex < this.text.length) {
            this.timer += dt;
            if(this.timer > 0.02) { // Print speed
                this.timer = 0;
                this.displayed += this.text[this.charIndex];
                this.charIndex++;
                this.el.innerHTML = this.displayed;
            }
            if(Input.isJustPressed('z') || Input.isJustPressed('enter')) {
                // Skip to end
                this.displayed = this.text;
                this.charIndex = this.text.length;
                this.el.innerHTML = this.displayed;
                Input.clearJustPressed('z');
                Input.clearJustPressed('enter');
            }
        } else {
            // Wait for input to advance
            if(Input.isJustPressed('z') || Input.isJustPressed('enter')) {
                this.hide();
                Input.clearJustPressed('z');
                Input.clearJustPressed('enter');
            }
        }
    }
};

// ==========================================
// MAP ENGINE
// ==========================================
const MapEngine = {
    player: { x: 7, y: 5, dir: 'down', moving: false, tx: 7, ty: 5, frame: 0 },
    npc: { x: 7, y: 2, dir: 'down', msg: "I challenge you to a Pokemon battle!" },
    mapData: [],

    init() {
        for(let y=0; y<10; y++) {
            let row = [];
            for(let x=0; x<15; x++) {
                // Create a path surrounded by trees/grass
                if(x < 2 || x > 12 || y < 1 || y > 8) row.push(1); // Tree
                else row.push(0); // Grass
            }
            this.mapData.push(row);
        }
    },
    update(dt) {
        if(Dialog.active || GameLoop.state !== 'MAP') return;

        // Movement
        if(!this.player.moving) {
            let dx = 0, dy = 0;
            if(Input.isDown('arrowleft')) { dx = -1; this.player.dir = 'left'; }
            else if(Input.isDown('arrowright')) { dx = 1; this.player.dir = 'right'; }
            else if(Input.isDown('arrowup')) { dy = -1; this.player.dir = 'up'; }
            else if(Input.isDown('arrowdown')) { dy = 1; this.player.dir = 'down'; }

            if(dx !== 0 || dy !== 0) {
                let nx = this.player.x + dx;
                let ny = this.player.y + dy;
                // Collision check
                if(this.mapData[ny] && this.mapData[ny][nx] === 0 && !(this.npc.x === nx && this.npc.y === ny)) {
                    this.player.tx = nx;
                    this.player.ty = ny;
                    this.player.moving = true;
                }
            }

            // Interaction
            if(Input.isJustPressed('z') || Input.isJustPressed('enter')) {
                let fx = this.player.x, fy = this.player.y;
                if(this.player.dir === 'left') fx--;
                if(this.player.dir === 'right') fx++;
                if(this.player.dir === 'up') fy--;
                if(this.player.dir === 'down') fy++;

                if(this.npc.x === fx && this.npc.y === fy) {
                    // Turn NPC to face player
                    if(this.player.dir === 'left') this.npc.dir = 'right';
                    if(this.player.dir === 'right') this.npc.dir = 'left';
                    if(this.player.dir === 'up') this.npc.dir = 'down';
                    if(this.player.dir === 'down') this.npc.dir = 'up';

                    Dialog.show(this.npc.msg, () => {
                        GameLoop.startTransition();
                    });
                }
            }
        } else {
            // Animate movement
            let speed = 4 * dt;
            this.player.frame += 12 * dt;
            let arrived = false;

            if(this.player.x < this.player.tx) { this.player.x += speed; if(this.player.x >= this.player.tx) arrived = true; }
            else if(this.player.x > this.player.tx) { this.player.x -= speed; if(this.player.x <= this.player.tx) arrived = true; }
            else if(this.player.y < this.player.ty) { this.player.y += speed; if(this.player.y >= this.player.ty) arrived = true; }
            else if(this.player.y > this.player.ty) { this.player.y -= speed; if(this.player.y <= this.player.ty) arrived = true; }

            if(arrived) {
                this.player.x = this.player.tx;
                this.player.y = this.player.ty;
                this.player.moving = false;
                this.player.frame = 0;
            }
        }
    },
    draw(ctx) {
        // Tiles
        for(let y=0; y<10; y++) {
            for(let x=0; x<15; x++) {
                if(this.mapData[y][x] === 1) {
                    ctx.fillStyle = '#228B22'; // Tree
                    ctx.fillRect(x*TILE_SIZE, y*TILE_SIZE, TILE_SIZE, TILE_SIZE);
                    ctx.fillStyle = '#006400';
                    ctx.fillRect(x*TILE_SIZE+4, y*TILE_SIZE+4, 8, 8);
                } else {
                    ctx.fillStyle = '#90EE90'; // Grass
                    ctx.fillRect(x*TILE_SIZE, y*TILE_SIZE, TILE_SIZE, TILE_SIZE);
                    // Little grass spots
                    if((x+y)%3 === 0) {
                        ctx.fillStyle = '#3CB371';
                        ctx.fillRect(x*TILE_SIZE+2, y*TILE_SIZE+2, 4, 4);
                    }
                }
            }
        }

        // Draw character helper
        const drawChar = (cx, cy, color, dir, isMoving, frame) => {
            let px = cx * TILE_SIZE;
            let py = cy * TILE_SIZE;
            let bounce = isMoving ? Math.abs(Math.sin(frame))*2 : 0;

            ctx.fillStyle = color; // Body
            ctx.fillRect(px+2, py-4-bounce, 12, 16);

            ctx.fillStyle = '#FFE4C4'; // Face
            if(dir === 'down') ctx.fillRect(px+4, py-2-bounce, 8, 6);
            if(dir === 'left') ctx.fillRect(px+2, py-2-bounce, 6, 6);
            if(dir === 'right') ctx.fillRect(px+8, py-2-bounce, 6, 6);
            if(dir === 'up') ctx.fillRect(px+4, py-4-bounce, 8, 4);
        };

        // Draw NPC
        drawChar(this.npc.x, this.npc.y, '#FF4500', this.npc.dir, false, 0);

        // Draw Player
        drawChar(this.player.x, this.player.y, '#1E90FF', this.player.dir, this.player.moving, this.player.frame);
    }
};

// ==========================================
// BATTLE ENGINE
// ==========================================
const BattleEngine = {
    state: 'INTRO',
    menuState: 'MAIN',
    cursor: 0,

    playerMon: null,
    enemyMon: null,

    msgQueue: [],
    onEnd: null,

    animTimer: 0,
    playerShake: 0, enemyShake: 0,
    playerFlash: false, enemyFlash: false,

    dispPlayerHp: 0, dispEnemyHp: 0,

    typeChart: {
        'Normal': {},
        'Fire': { 'Grass': 2, 'Water': 0.5, 'Fire': 0.5, 'Ice': 2 },
        'Water': { 'Fire': 2, 'Grass': 0.5, 'Water': 0.5 },
        'Grass': { 'Water': 2, 'Fire': 0.5, 'Grass': 0.5 },
        'Electric': { 'Water': 2, 'Grass': 0.5, 'Electric': 0.5 },
        'Ice': { 'Grass': 2, 'Fire': 0.5, 'Water': 0.5 }
    },

    init() {
        // Gen 3 stats prototype
        this.playerMon = {
            name: 'MUDKIP', level: 5, types: ['Water'], hp: 20, maxHp: 20,
            atk: 13, def: 11, spa: 11, spd: 11, spe: 10,
            moves: [
                { name: 'TACKLE', type: 'Normal', power: 40, maxPp: 35, pp: 35 },
                { name: 'WATER GUN', type: 'Water', power: 40, maxPp: 25, pp: 25 }
            ]
        };
        this.enemyMon = {
            name: 'TREECKO', level: 5, types: ['Grass'], hp: 20, maxHp: 20,
            atk: 10, def: 10, spa: 13, spd: 12, spe: 13,
            moves: [
                { name: 'POUND', type: 'Normal', power: 40, maxPp: 35, pp: 35 },
                { name: 'ABSORB', type: 'Grass', power: 20, maxPp: 25, pp: 25 }
            ]
        };
        this.dispPlayerHp = this.playerMon.hp;
        this.dispEnemyHp = this.enemyMon.hp;
        this.msgQueue = [];
    },

    start(onEnd) {
        this.init();
        this.state = 'INTRO';
        this.onEnd = onEnd;
        this.queueMessage(`Wild ${this.enemyMon.name} appeared!`);
        this.queueMessage(`Go! ${this.playerMon.name}!`, () => {
            this.state = 'MENU';
            this.menuState = 'MAIN';
            this.cursor = 0;
            Input.clearJustPressed('z');
            Input.clearJustPressed('enter');
        });
    },

    queueMessage(text, callback) {
        this.msgQueue.push({ text, callback });
    },

    getEffectiveness(moveType, targetTypes) {
        let eff = 1;
        targetTypes.forEach(t => {
            if(this.typeChart[moveType] && this.typeChart[moveType][t] !== undefined) {
                eff *= this.typeChart[moveType][t];
            }
        });
        return eff;
    },

    calculateDamage(attacker, defender, move) {
        let isSpecial = SPECIAL_TYPES.includes(move.type);
        let A = isSpecial ? attacker.spa : attacker.atk;
        let D = isSpecial ? defender.spd : defender.def;

        let crit = Math.random() < 0.0625 ? 2 : 1; // 1/16 crit chance
        let baseDmg = ((2 * attacker.level / 5 + 2) * move.power * A / D) / 50 + 2;

        let stab = attacker.types.includes(move.type) ? 1.5 : 1;
        let eff = this.getEffectiveness(move.type, defender.types);
        let random = (Math.floor(Math.random() * 16) + 85) / 100;

        let damage = Math.floor(baseDmg * crit * stab * eff * random);
        if(damage < 1 && eff > 0) damage = 1;
        if(eff === 0) damage = 0;

        return { damage, crit: crit > 1, eff };
    },

    update(dt) {
        // Animations
        if(this.dispPlayerHp > this.playerMon.hp) this.dispPlayerHp = Math.max(this.playerMon.hp, this.dispPlayerHp - 10*dt);
        if(this.dispEnemyHp > this.enemyMon.hp) this.dispEnemyHp = Math.max(this.enemyMon.hp, this.dispEnemyHp - 10*dt);

        if(this.playerShake > 0) this.playerShake -= dt * 10; else this.playerShake = 0;
        if(this.enemyShake > 0) this.enemyShake -= dt * 10; else this.enemyShake = 0;

        if(Dialog.active) return; // Wait for text
        Input.locked = false;

        if(this.msgQueue.length > 0 && this.state !== 'ATTACK_ANIM') {
            let msg = this.msgQueue.shift();
            Dialog.show(msg.text, () => { if(msg.callback) msg.callback(); });
            return;
        }

        if(this.state === 'MENU') {
            if(this.menuState === 'MAIN') {
                if(Input.isJustPressed('arrowright')) this.cursor = (this.cursor + 1) % 2 + (this.cursor >= 2 ? 2 : 0);
                if(Input.isJustPressed('arrowleft')) this.cursor = (this.cursor + 1) % 2 + (this.cursor >= 2 ? 2 : 0);
                if(Input.isJustPressed('arrowdown')) this.cursor = (this.cursor + 2) % 4;
                if(Input.isJustPressed('arrowup')) this.cursor = (this.cursor + 2) % 4;

                if(Input.isJustPressed('z') || Input.isJustPressed('enter')) {
                    Input.clearJustPressed('z');
                    Input.clearJustPressed('enter');
                    if(this.cursor === 0) { // FIGHT
                        this.menuState = 'FIGHT';
                        this.cursor = 0;
                    } else if(this.cursor === 3) { // RUN
                        this.queueMessage("Got away safely!", () => { if(this.onEnd) this.onEnd(); });
                        this.state = 'MESSAGE';
                    } else {
                        this.queueMessage("Not implemented!");
                        this.state = 'MESSAGE';
                    }
                }
            } else if(this.menuState === 'FIGHT') {
                let mCount = this.playerMon.moves.length;
                if(Input.isJustPressed('arrowdown')) this.cursor = Math.min(this.cursor + 2, mCount - 1);
                if(Input.isJustPressed('arrowup')) this.cursor = Math.max(this.cursor - 2, 0);
                if(Input.isJustPressed('arrowright') && this.cursor % 2 === 0 && this.cursor + 1 < mCount) this.cursor++;
                if(Input.isJustPressed('arrowleft') && this.cursor % 2 === 1) this.cursor--;

                if(Input.isJustPressed('x')) { // CANCEL
                    this.menuState = 'MAIN';
                    this.cursor = 0;
                    Input.clearJustPressed('x');
                } else if(Input.isJustPressed('z') || Input.isJustPressed('enter')) {
                    Input.clearJustPressed('z');
                    Input.clearJustPressed('enter');
                    this.executeTurn(this.playerMon.moves[this.cursor]);
                }
            }
        } else if(this.state === 'ATTACK_ANIM') {
            Input.locked = true;
            this.animTimer -= dt;
            if(this.animTimer <= 0) {
                this.state = 'MESSAGE';
                Input.locked = false;
            }
        }
    },

    executeTurn(playerMove) {
        this.state = 'MESSAGE';

        // Enemy AI (Strict: prioritize super effective, else highest damage)
        let enemyMove = this.enemyMon.moves[0];
        let maxExpectedDmg = -1;
        for(let m of this.enemyMon.moves) {
            let eff = this.getEffectiveness(m.type, this.playerMon.types);
            let dmg = this.calculateDamage(this.enemyMon, this.playerMon, m).damage;
            // Heavily weight super effective moves
            if(eff > 1) dmg += 1000; 
            if(dmg > maxExpectedDmg) { maxExpectedDmg = dmg; enemyMove = m; }
        }

        // Speed tie break
        let pFirst = this.playerMon.spe >= this.enemyMon.spe;
        let first = pFirst ? { mon: this.playerMon, move: playerMove, isPlayer: true } : { mon: this.enemyMon, move: enemyMove, isPlayer: false };
        let second = pFirst ? { mon: this.enemyMon, move: enemyMove, isPlayer: false } : { mon: this.playerMon, move: playerMove, isPlayer: true };

        const executeAttack = (attacker, defender, move, isPlayer, onDone) => {
            if(attacker.hp <= 0) return onDone();
            this.queueMessage(`${attacker.name} used ${move.name}!`, () => {
                let res = this.calculateDamage(attacker, defender, move);

                // Trigger Anim
                this.state = 'ATTACK_ANIM';
                this.animTimer = 0.5;
                if(isPlayer) {
                    this.enemyShake = 1; this.enemyFlash = true;
                    setTimeout(() => this.enemyFlash = false, 100);
                    setTimeout(() => this.enemyFlash = true, 200);
                    setTimeout(() => this.enemyFlash = false, 300);
                } else {
                    this.playerShake = 1; this.playerFlash = true;
                    setTimeout(() => this.playerFlash = false, 100);
                    setTimeout(() => this.playerFlash = true, 200);
                    setTimeout(() => this.playerFlash = false, 300);
                }

                // Wait for anim to finish using a safe interval check
                let check = setInterval(() => {
                    if(this.state !== 'ATTACK_ANIM') {
                        clearInterval(check);
                        defender.hp = Math.max(0, defender.hp - res.damage);

                        if(res.eff > 1) this.queueMessage("It's super effective!");
                        else if(res.eff < 1 && res.eff > 0) this.queueMessage("It's not very effective...");
                        else if(res.eff === 0) this.queueMessage(`It doesn't affect ${defender.name}...`);

                        if(res.crit && res.eff > 0) this.queueMessage("A critical hit!");

                        onDone();
                    }
                }, 50);
            });
        };

        executeAttack(first.mon, first.isPlayer ? this.enemyMon : this.playerMon, first.move, first.isPlayer, () => {
            if(this.enemyMon.hp <= 0 || this.playerMon.hp <= 0) return this.checkFaint();
            executeAttack(second.mon, second.isPlayer ? this.enemyMon : this.playerMon, second.move, second.isPlayer, () => {
                this.checkFaint();
            });
        });
    },

    checkFaint() {
        if(this.enemyMon.hp <= 0) {
            this.queueMessage(`Wild ${this.enemyMon.name} fainted!`, () => {
                this.queueMessage("You won!", () => { if(this.onEnd) this.onEnd(); });
            });
        } else if(this.playerMon.hp <= 0) {
            this.queueMessage(`${this.playerMon.name} fainted!`, () => {
                this.queueMessage("You blacked out!", () => { if(this.onEnd) this.onEnd(); });
            });
        } else {
            this.state = 'MENU';
            this.menuState = 'MAIN';
            this.cursor = 0;
            Input.clearJustPressed('z');
            Input.clearJustPressed('enter');
        }
    },

    draw(ctx) {
        // Battle Background
        ctx.fillStyle = '#f8f8f8';
        ctx.fillRect(0,0,MAP_W, MAP_H);

        // Platforms (Classic Ellipses)
        ctx.fillStyle = '#9cd9a5'; // Light green platform
        ctx.beginPath(); ctx.ellipse(180, 55, 50, 15, 0, 0, Math.PI*2); ctx.fill(); // Enemy Platform
        ctx.beginPath(); ctx.ellipse(60, 110, 60, 20, 0, 0, Math.PI*2); ctx.fill(); // Player Platform

        // Sprites
        if(!this.enemyFlash && this.enemyMon.hp > 0) {
            let ex = 145 + Math.sin(this.enemyShake * 20) * 4;
            let ey = 0;
            if(AssetManager.images['enemy_front']) {
                ctx.drawImage(AssetManager.images['enemy_front'], ex, ey, 72, 72);
            }
        }
        if(!this.playerFlash && this.playerMon.hp > 0) {
            let px = 20 + Math.sin(this.playerShake * 20) * 4;
            let py = 50;
            if(AssetManager.images['player_back']) {
                ctx.drawImage(AssetManager.images['player_back'], px, py, 72, 72);
            }
        }

        // Draw HUD HP Bars (Trapezoidal frame approximation)
        const drawHUD = (x, y, name, level, hp, maxHp, dispHp) => {
            ctx.fillStyle = '#fff';
            ctx.strokeStyle = '#4a4a4a';
            ctx.lineWidth = 1;

            // Frame Shape
            ctx.beginPath();
            ctx.moveTo(x+5, y);
            ctx.lineTo(x+115, y);
            ctx.lineTo(x+110, y+35);
            ctx.lineTo(x, y+35);
            ctx.closePath();
            ctx.fill(); ctx.stroke();

            // Text
            ctx.fillStyle = '#4a4a4a';
            ctx.font = '10px "Courier New"';
            ctx.fillText(name, x+10, y+14);
            ctx.fillText(`Lv${level}`, x+80, y+14);

            // HP Bar Background
            let barX = x + 35;
            let barY = y + 20;
            let barW = 60;
            let barH = 4;

            ctx.fillStyle = '#4a4a4a';
            ctx.fillRect(barX-2, barY-2, barW+4, barH+4);

            // HP Bar Fill
            let hpRatio = dispHp / maxHp;
            ctx.fillStyle = hpRatio > 0.5 ? '#18C020' : (hpRatio > 0.2 ? '#F8D030' : '#F85838');
            ctx.fillRect(barX, barY, Math.max(0, barW * hpRatio), barH);
        };

        if(this.enemyMon.hp > 0 || this.dispEnemyHp > 0) drawHUD(10, 10, this.enemyMon.name, this.enemyMon.level, this.enemyMon.hp, this.enemyMon.maxHp, this.dispEnemyHp);
        if(this.playerMon.hp > 0 || this.dispPlayerHp > 0) drawHUD(120, 85, this.playerMon.name, this.playerMon.level, this.playerMon.hp, this.playerMon.maxHp, this.dispPlayerHp);

        // Action Panel
        if(this.state === 'MENU' && !Dialog.active) {
            let panelH = 40;
            let panelY = MAP_H - panelH;

            // Bottom bar bg
            ctx.fillStyle = '#285068';
            ctx.fillRect(0, panelY, MAP_W, panelH);
            ctx.fillStyle = '#f8f8f8';
            ctx.fillRect(2, panelY+2, MAP_W-4, panelH-4);

            ctx.fillStyle = '#4a4a4a';
            ctx.font = 'bold 12px "Courier New"';

            if(this.menuState === 'MAIN') {
                ctx.fillText(`What will`, 10, panelY + 16);
                ctx.fillText(`${this.playerMon.name} do?`, 10, panelY + 30);

                // Menu Box
                ctx.fillStyle = '#fff';
                ctx.fillRect(110, panelY, 130, panelH);
                ctx.strokeRect(110, panelY, 130, panelH);

                ctx.fillStyle = '#4a4a4a';
                ctx.fillText("FIGHT", 130, panelY + 16);
                ctx.fillText("BAG", 190, panelY + 16);
                ctx.fillText("POKEMON", 130, panelY + 30);
                ctx.fillText("RUN", 190, panelY + 30);

                let cx = 120 + (this.cursor % 2) * 60;
                let cy = panelY + 16 + Math.floor(this.cursor / 2) * 14;
                ctx.fillText("▶", cx, cy);
            } else if(this.menuState === 'FIGHT') {
                // Moves
                for(let i=0; i<this.playerMon.moves.length; i++) {
                    let m = this.playerMon.moves[i];
                    let mx = 20 + (i%2)*80;
                    let my = panelY + 16 + Math.floor(i/2)*14;
                    ctx.fillText(m.name, mx, my);
                }
                let cx = 8 + (this.cursor % 2)*80;
                let cy = panelY + 16 + Math.floor(this.cursor / 2)*14;
                ctx.fillText("▶", cx, cy);

                // Move Details Box
                ctx.fillStyle = '#fff';
                ctx.fillRect(160, panelY, 80, panelH);
                ctx.strokeRect(160, panelY, 80, panelH);

                let activeMove = this.playerMon.moves[this.cursor];
                ctx.fillStyle = '#4a4a4a';
                ctx.font = '10px "Courier New"';
                ctx.fillText(`TYPE/${activeMove.type}`, 165, panelY + 14);
                ctx.fillText(`PP  ${activeMove.pp}/${activeMove.maxPp}`, 165, panelY + 28);
            }
        }
    }
};

// ==========================================
// GAME LOOP & TRANSITION
// ==========================================
const GameLoop = {
    state: 'MAP', // MAP, TRANSITION, BATTLE
    lastTime: 0,
    ctx: null,
    transitionTimer: 0,

    init() {
        const canvas = document.getElementById('game-canvas');
        this.ctx = canvas.getContext('2d');
        this.ctx.imageSmoothingEnabled = false; // Pixel art!

        Dialog.init();
        MapEngine.init();

        AssetManager.preloadAll(() => {
            requestAnimationFrame(t => this.loop(t));
        });
    },

    startTransition() {
        this.state = 'TRANSITION';
        this.transitionTimer = 0;
    },

    loop(time) {
        let dt = (time - this.lastTime) / 1000;
        if(dt > 0.1) dt = 0.1; // Limit dt for lag
        this.lastTime = time;

        Input.update();
        Dialog.update(dt);

        if(this.state === 'MAP') {
            MapEngine.update(dt);
            MapEngine.draw(this.ctx);
        } else if(this.state === 'TRANSITION') {
            this.transitionTimer += dt;
            MapEngine.draw(this.ctx);

            // GBA Style Encounter Flash Effect
            if(this.transitionTimer < 1.0) {
                if(Math.floor(this.transitionTimer * 15) % 2 === 0) {
                    this.ctx.fillStyle = 'rgba(0,0,0,0.6)';
                    this.ctx.fillRect(0,0,MAP_W,MAP_H);
                }
            } else if(this.transitionTimer < 2.0) {
                // Blackout shrinking circle (Mosaic is hard on 2D canvas without heavy pixel manipulation)
                let progress = this.transitionTimer - 1.0;
                let radius = (MAP_W/2) * (1 - progress);

                this.ctx.fillStyle = '#000';
                this.ctx.fillRect(0,0,MAP_W, MAP_H);

                if(radius > 0) {
                    this.ctx.save();
                    // Fallback using composite operation
                    this.ctx.globalCompositeOperation = 'destination-out';
                    this.ctx.beginPath();
                    this.ctx.arc(MAP_W/2, MAP_H/2, radius, 0, Math.PI*2);
                    this.ctx.fill();
                    this.ctx.restore();
                }
            } else {
                this.state = 'BATTLE';
                BattleEngine.start(() => {
                    this.state = 'MAP';
                    MapEngine.player.moving = false; // reset interaction state
                });
            }
        } else if(this.state === 'BATTLE') {
            BattleEngine.update(dt);
            BattleEngine.draw(this.ctx);
        }

        requestAnimationFrame(t => this.loop(t));
    }
};

// Start
window.onload = () => GameLoop.init();

</script>
</body>
</html>","path":"game.html"}

